INSERT INTO `question` (`category_id`, `type`, `content`, `options`, `answer`, `analysis`, `difficulty`, `chapter`, `knowledge_point`) VALUES
(3, '单选题', '驾驶机动车在道路上违反道路交通安全法的行为，属于什么行为？', '{"A":"违章行为","B":"违法行为","C":"过失行为","D":"违规行为"}', 'B', '根据《道路交通安全法》规定，违反道路交通安全法律、法规的行为属于违法行为。', 2, '道路交通安全法律法规', '法律基础知识'),
(3, '单选题', '机动车驾驶人初次申领驾驶证后的实习期是多长时间？', '{"A":"6个月","B":"12个月","C":"18个月","D":"24个月"}', 'B', '机动车驾驶人初次申领机动车驾驶证后的12个月为实习期。', 1, '道路交通安全法律法规', '驾驶证管理'),
(3, '单选题', '道路交通安全违法行为累积记分周期为多长时间？', '{"A":"6个月","B":"12个月","C":"18个月","D":"24个月"}', 'B', '道路交通安全违法行为累积记分周期为12个月，从机动车驾驶证初次领取之日起计算。', 1, '道路交通安全法律法规', '记分制度'),
(4, '单选题', '交通信号灯由红灯、绿灯和黄灯组成，红灯表示什么？', '{"A":"禁止通行","B":"准许通行","C":"警示","D":"停止通行"}', 'D', '红灯表示禁止通行，但右转弯的车辆在不妨碍被放行的车辆、行人通行的情况下，可以通行。', 1, '道路交通信号', '交通信号灯'),
(4, '单选题', '交通信号灯黄灯闪烁时，车辆、行人应怎样通行？', '{"A":"不准通行，但已越过停止线的车辆和已进入人行横道的行人可以继续通行","B":"在确保安全的原则下通行","C":"加速通行","D":"停车等待"}', 'B', '黄灯闪烁时，车辆、行人在确保安全的原则下通行。', 2, '道路交通信号', '交通信号灯'),
(4, '单选题', '红色叉形灯或者箭头灯亮时，表示什么？', '{"A":"本车道禁止车辆通行","B":"其他车道禁止车辆通行","C":"本车道准许车辆通行","D":"所有车道禁止车辆通行"}', 'A', '红色叉形灯或者箭头灯亮时，本车道禁止车辆通行。', 2, '道路交通信号', '车道信号灯'),
(5, '单选题', '驾驶机动车在没有道路中心线的道路上行驶，应当在道路的哪侧通行？', '{"A":"左侧","B":"右侧","C":"中间","D":"任意一侧"}', 'B', '在没有划分机动车道、非机动车道和人行道的道路上，机动车在道路中间通行，但应当靠右侧行驶。', 1, '安全行车、文明驾驶', '通行规则'),
(5, '单选题', '机动车在道路上变更车道需要注意什么？', '{"A":"提前开启转向灯","B":"加速行驶","C":"随意变更","D":"紧急制动"}', 'A', '机动车在变更车道时，应当提前开启转向灯，确认安全后驶入需要变更的车道。', 2, '安全行车、文明驾驶', '变更车道'),
(5, '单选题', '机动车在道路上发生故障，需要停车排除时，驾驶人应当立即开启什么灯？', '{"A":"左转向灯","B":"右转向灯","C":"危险报警闪光灯","D":"前照灯"}', 'C', '机动车在道路上发生故障，需要停车排除时，驾驶人应当立即开启危险报警闪光灯，将机动车移至不妨碍交通的地方停放。', 2, '安全行车、文明驾驶', '故障处置'),
(6, '单选题', '机动车在紧急制动时ABS系统会起到什么作用？', '{"A":"切断动力输出","B":"防止车轮抱死","C":"减轻车辆惯性","D":"自动控制方向"}', 'B', 'ABS系统即防抱死制动系统，可防止车轮抱死，使车辆在制动时仍能转向，保证车辆的转向稳定性。', 3, '机动车驾驶操作相关基础知识', '制动系统'),
(6, '单选题', '机动车在夜间行驶，路灯照明良好时，应当使用什么灯光？', '{"A":"远光灯","B":"近光灯","C":"危险报警闪光灯","D":"示廓灯"}', 'B', '机动车在夜间行驶，路灯照明良好时，应当使用近光灯。', 2, '机动车驾驶操作相关基础知识', '灯光使用'),
(6, '单选题', '机动车驶近急弯、坡道顶端等影响安全视距的路段时，应当怎样做？', '{"A":"快速通过","B":"使用危险报警闪光灯","C":"减速慢行并鸣喇叭示意","D":"随意通行"}', 'C', '机动车驶近急弯、坡道顶端等影响安全视距的路段时，应当减速慢行并鸣喇叭示意。', 2, '机动车驾驶操作相关基础知识', '安全驾驶'),
(7, '单选题', '在暴雨天气驾车，刮水器无法刮净雨水时，应怎样做？', '{"A":"减速行驶","B":"集中注意力谨慎驾驶","C":"立即减速靠边停驶","D":"以正常速度行驶"}', 'C', '在暴雨天气驾车，刮水器无法刮净雨水时，应立即减速靠边停驶，开启危险报警闪光灯，待雨势减弱后再行驶。', 3, '恶劣气象和复杂道路条件下的驾驶常识', '恶劣天气驾驶'),
(7, '单选题', '在大雨天行车，为避免发生"水滑"而造成危险，要控制速度行驶。', '{"A":"正确","B":"错误"}', 'A', '在大雨天行车，为避免发生"水滑"而造成危险，要控制速度行驶，降低车速，避免紧急制动。', 2, '恶劣气象和复杂道路条件下的驾驶常识', '雨天驾驶'),
(8, '单选题', '车辆发生碰撞时，关于安全带作用的说法错误的是什么？', '{"A":"保护颈部不受伤害","B":"减轻驾乘人员受伤程度","C":"减轻驾驶人疲劳","D":"保持正确驾驶姿势"}', 'C', '安全带的作用是保护驾乘人员安全，减轻受伤程度，但不能减轻驾驶人疲劳。', 2, '紧急情况避险', '安全装置'),
(8, '单选题', '在高速公路上发生紧急情况，不要轻易急转方向避让，应采取制动减速，使车辆在碰撞前处于停止或低速行进状态，以减小碰撞损坏程度。', '{"A":"正确","B":"错误"}', 'A', '在高速公路上发生紧急情况，不要轻易急转方向避让，应采取制动减速，以减小碰撞损坏程度。', 3, '紧急情况避险', '紧急避险'),
(9, '单选题', '发生交通事故后，防止二次事故的有效措施是什么？', '{"A":"放置警告标志","B":"开启危险报警闪光灯","C":"人员转移到安全地点","D":"以上都是"}', 'D', '发生交通事故后，应立即开启危险报警闪光灯，在车后放置警告标志，人员转移到安全地点，防止二次事故。', 2, '交通事故处置', '事故处理');
